", "import { isTruthy } from '../util';

/**
 * Handle saved filter change event.
 *
 * @param event "change" event for the saved filter select
 */
function handleSavedFilterChange(event: Event): void {
  const savedFilter = event.currentTarget as HTMLSelectElement;
  let baseUrl = savedFilter.baseURI.split('?')[0];
  const preFilter = '?';

  const selectedOptions = Array.from(savedFilter.options)
    .filter(option => option.selected)
    .map(option => `filter_id=${option.value}`)
    .join('&');

  baseUrl += `${preFilter}${selectedOptions}`;
  document.location.href = baseUrl;
}

export function initSavedFilterSelect(): void {
  const divResults = document.getElementById('results');
  if (isTruthy(divResults)) {
    const savedFilterSelect = document.getElementById('saved-filter-select');
    if (isTruthy(savedFilterSelect)) {
      savedFilterSelect.addEventListener('change', handleSavedFilterChange);
    }
  }
}
", "const HOTKEYS: Record<string, () => void> = {
  '/': focusGlobalSearch,
};

function focusGlobalSearch(): void {
  const searchInput = document.querySelector<HTMLInputElement>('header input[name="q"]')!;
  if (searchInput) {
    searchInput.focus();
  }
}

function handleKeydown(event: KeyboardEvent): void {
  // Ignore hotkeys when focused on form elements or when modal is open
  if ((event.target as Element).matches('input, textarea, select') || document.body.classList.contains('modal-open')) {
    return;
  }

  const handler = HOTKEYS[event.key];
  if (!handler) {
    return;
  }

  event.preventDefault();
  handler();
}

export function initHotkeys(): void {
  document.addEventListener('keydown', handleKeydown);
}
", "import { initForms } from './forms';
import { initBootstrap } from './bs';
import { initQuickSearch } from './search';
import { initSelects } from './select';
import { initButtons } from './buttons';
import { initColorMode } from './colorMode';
import { initMessages } from './messages';
import { initClipboard } from './clipboard';
import { initDateSelector } from './dateSelector';
import { initTableConfig } from './tableConfig';
import { initSideNav } from './sidenav';
import { initDashboard } from './dashboard';
import { initRackElevation } from './racks';
import { initHtmx } from './htmx';
import { initSavedFilterSelect } from './forms/savedFiltersSelect';
import { initHotkeys } from './hotkeys';

function initDocument(): void {
  for (const init of [
    initBootstrap,
    initColorMode,
    initMessages,
    initForms,
    initQuickSearch,
    initSelects,
    initDateSelector,
    initButtons,
    initClipboard,
    initTableConfig,
    initSideNav,
    initDashboard,
    initRackElevation,
    initHtmx,
    initSavedFilterSelect,
    initHotkeys,
  ]) {
    init();
  }
}

function initWindow(): void {
  const documentForms = document.forms;
  for (const documentForm of documentForms) {
    if (documentForm.method.toUpperCase() == 'GET') {
      documentForm.addEventListener('formdata', function (event: FormDataEvent) {
        const formData: FormData = event.formData;
        for (const [name, value] of Array.from(formData.entries())) {
          if (value === '') formData.delete(name);
        }
      });
    }
  }

  const contentContainer = document.querySelector<HTMLElement>('.content-container');
  if (contentContainer !== null) {
    // Focus the content container for accessible navigation.
    contentContainer.focus();
  }
}

window.addEventListener('load', initWindow);

if (document.readyState !== 'loading') {
  initDocument();
} else {
  document.addEventListener('DOMContentLoaded', initDocument);
}
